/**
 * Shared routing/context-injection helpers.
 *
 * Used by:
 *   - plugins/edc/hooks/session-start.mjs (Claude Code, Cursor)
 *   - plugins/edc/hooks/pretooluse-context-inject.mjs (Claude Code, Cursor)
